import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { sortNotesByUpdatedAt } from './sortNotesByUpdatedAt';

describe('sortNotesByUpdatedAt', () => {
  beforeEach(() => {
    vi.restoreAllMocks();
  });

  it('should handle happy path: sorts notes descending by updatedAt', () => {
    const notes = [
      { id: 1, title: 'Note A', updatedAt: '2023-01-01T10:00:00Z' },
      { id: 2, title: 'Note B', updatedAt: '2023-01-03T12:00:00Z' },
      { id: 3, title: 'Note C', updatedAt: '2023-01-02T08:30:00Z' },
    ];

    const sorted = sortNotesByUpdatedAt(notes);

    expect(sorted).toEqual([
      { id: 2, title: 'Note B', updatedAt: '2023-01-03T12:00:00Z' },
      { id: 3, title: 'Note C', updatedAt: '2023-01-02T08:30:00Z' },
      { id: 1, title: 'Note A', updatedAt: '2023-01-01T10:00:00Z' },
    ]);
  });

  it('should handle edge case: notes with same updatedAt retain original order', () => {
    const notes = [
      { id: 1, title: 'First', updatedAt: '2023-05-01T00:00:00Z' },
      { id: 2, title: 'Second', updatedAt: '2023-05-01T00:00:00Z' },
    ];

    const sorted = sortNotesByUpdatedAt(notes);

    // Stable sort expectation: original order preserved when timestamps are equal
    expect(sorted).toEqual([
      { id: 1, title: 'First', updatedAt: '2023-05-01T00:00:00Z' },
      { id: 2, title: 'Second', updatedAt: '2023-05-01T00:00:00Z' },
    ]);
  });

  it('should handle null/empty inputs: returns empty array for undefined, null, empty string, or 0', () => {
    // undefined
    expect(sortNotesByUpdatedAt(undefined as any)).toEqual([]);

    // null
    expect(sortNotesByUpdatedAt(null as any)).toEqual([]);

    // empty string (treated as non‑array)
    expect(sortNotesByUpdatedAt('' as any)).toEqual([]);

    // numeric zero (treated as non‑array)
    expect(sortNotesByUpdatedAt(0 as any)).toEqual([]);
  });
});

