import { describe, it, expect } from 'vitest';
import { countWords } from './path/to/module';

describe('countWords', () => {
  it('should handle happy path with a normal sentence', () => {
    const result = countWords('The quick brown fox jumps over the lazy dog');
    expect(result).toBe(9);
  });

  it('should handle edge case with multiple spaces and newline characters', () => {
    const result = countWords('   Hello   world \n this   is\t a test  ');
    // Words: Hello, world, this, is, a, test => 6
    expect(result).toBe(6);
  });

  it('should handle null/empty inputs gracefully', () => {
    expect(countWords()).toBe(0);
    expect(countWords(undefined as unknown as string)).toBe(0);
    expect(countWords(null as unknown as string)).toBe(0);
    expect(countWords('')).toBe(0);
    expect(countWords('   ')).toBe(0);
  });
});